"""Application entrypoint for Evidence Gate."""

from __future__ import annotations

from contextlib import asynccontextmanager
from functools import lru_cache

from fastapi import FastAPI

from evidence_gate.audit.store import FileAuditStore
from evidence_gate.config import Settings, get_settings
from evidence_gate.decision.models import KnowledgeBaseMaintenanceRunRequest
from evidence_gate.decision.service import DecisionService


@lru_cache(maxsize=1)
def get_audit_store() -> FileAuditStore:
    settings = get_settings()
    return FileAuditStore(settings.audit_root)


@lru_cache(maxsize=1)
def get_decision_service() -> DecisionService:
    settings: Settings = get_settings()
    return DecisionService(settings=settings, audit_store=get_audit_store())


@asynccontextmanager
async def app_lifespan(_app: FastAPI):
    settings = get_settings()
    if settings.maintenance.enabled and settings.maintenance.prune_on_startup:
        get_decision_service().run_knowledge_base_maintenance(KnowledgeBaseMaintenanceRunRequest())
    yield


def create_app() -> FastAPI:
    settings = get_settings()
    app = FastAPI(title=settings.app_name, version=settings.version, lifespan=app_lifespan)

    @app.get("/health")
    def health() -> dict[str, str]:
        return {"status": "ok", "service": settings.app_name, "version": settings.version}

    from evidence_gate.api.routes import router

    app.include_router(router)
    return app


app = create_app()

"""HTTP routes for the Evidence Gate alpha service."""

from __future__ import annotations

from fastapi import APIRouter, Depends, HTTPException, Response, status

from evidence_gate.api.main import get_decision_service
from evidence_gate.decision.models import (
    ActionDecisionRequest,
    ActionDecisionResponse,
    ChangeImpactRequest,
    DecisionRecord,
    KnowledgeBaseIngestRequest,
    KnowledgeBaseIngestResponse,
    KnowledgeBaseListResponse,
    KnowledgeBaseMaintenanceRunRequest,
    KnowledgeBaseMaintenanceRunResponse,
    KnowledgeBaseMaintenanceStatusResponse,
    KnowledgeBasePruneRequest,
    KnowledgeBasePruneResponse,
    KnowledgeBaseRemovalResponse,
    KnowledgeBaseStatusResponse,
    QueryDecisionRequest,
)
from evidence_gate.decision.service import DecisionService

router = APIRouter()


@router.post("/v1/decide/query", response_model=DecisionRecord)
def decide_query(
    request: QueryDecisionRequest,
    service: DecisionService = Depends(get_decision_service),
) -> DecisionRecord:
    try:
        return service.decide_query(request)
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc


@router.post("/v1/decide/change-impact", response_model=DecisionRecord)
def decide_change_impact(
    request: ChangeImpactRequest,
    service: DecisionService = Depends(get_decision_service),
) -> DecisionRecord:
    try:
        return service.decide_change_impact(request)
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc


@router.post("/v1/decide/action", response_model=ActionDecisionResponse)
def decide_action(
    request: ActionDecisionRequest,
    response: Response,
    service: DecisionService = Depends(get_decision_service),
) -> ActionDecisionResponse:
    try:
        result = service.decide_action(request)
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    response.status_code = status.HTTP_200_OK if result.allowed else status.HTTP_403_FORBIDDEN
    return result


@router.get("/v1/decisions/{decision_id}", response_model=DecisionRecord)
def get_decision(
    decision_id: str,
    service: DecisionService = Depends(get_decision_service),
) -> DecisionRecord:
    record = service.get_decision(decision_id)
    if record is None:
        raise HTTPException(status_code=404, detail=f"Decision not found: {decision_id}")
    return record


@router.post("/v1/knowledge-bases/ingest", response_model=KnowledgeBaseIngestResponse)
def ingest_knowledge_base(
    request: KnowledgeBaseIngestRequest,
    service: DecisionService = Depends(get_decision_service),
) -> KnowledgeBaseIngestResponse:
    try:
        return service.ingest_repository(request)
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc


@router.get("/v1/knowledge-bases", response_model=KnowledgeBaseListResponse)
def list_knowledge_bases(
    service: DecisionService = Depends(get_decision_service),
) -> KnowledgeBaseListResponse:
    return service.list_ingested_repositories()


@router.get("/v1/knowledge-bases/status", response_model=KnowledgeBaseStatusResponse)
def get_knowledge_base_status(
    repo_path: str,
    service: DecisionService = Depends(get_decision_service),
) -> KnowledgeBaseStatusResponse:
    try:
        return service.get_repository_ingest_status(repo_path)
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc


@router.delete("/v1/knowledge-bases", response_model=KnowledgeBaseRemovalResponse)
def delete_knowledge_base(
    repo_path: str,
    service: DecisionService = Depends(get_decision_service),
) -> KnowledgeBaseRemovalResponse:
    return service.delete_repository_ingest(repo_path)


@router.post("/v1/knowledge-bases/prune", response_model=KnowledgeBasePruneResponse)
def prune_knowledge_bases(
    request: KnowledgeBasePruneRequest,
    service: DecisionService = Depends(get_decision_service),
) -> KnowledgeBasePruneResponse:
    return service.prune_repository_ingests(request)


@router.get("/v1/knowledge-bases/maintenance/status", response_model=KnowledgeBaseMaintenanceStatusResponse)
def get_knowledge_base_maintenance_status(
    service: DecisionService = Depends(get_decision_service),
) -> KnowledgeBaseMaintenanceStatusResponse:
    return service.get_maintenance_status()


@router.post("/v1/knowledge-bases/maintenance/run", response_model=KnowledgeBaseMaintenanceRunResponse)
def run_knowledge_base_maintenance(
    request: KnowledgeBaseMaintenanceRunRequest,
    service: DecisionService = Depends(get_decision_service),
) -> KnowledgeBaseMaintenanceRunResponse:
    return service.run_knowledge_base_maintenance(request)

"""File-backed audit storage for decision records."""

from __future__ import annotations

from pathlib import Path

from evidence_gate.decision.models import DecisionRecord


class FileAuditStore:
    """Persist decisions to individual JSON files plus a JSONL ledger."""

    def __init__(self, root: Path):
        self.root = Path(root)
        self.decisions_dir = self.root / "decisions"
        self.ledger_path = self.root / "decisions.jsonl"
        self.decisions_dir.mkdir(parents=True, exist_ok=True)
        self.ledger_path.parent.mkdir(parents=True, exist_ok=True)

    def save(self, record: DecisionRecord) -> None:
        decision_path = self.decisions_dir / f"{record.decision_id}.json"
        decision_path.write_text(record.model_dump_json(indent=2), encoding="utf-8")
        with self.ledger_path.open("a", encoding="utf-8") as handle:
            handle.write(record.model_dump_json())
            handle.write("\n")

    def get(self, decision_id: str) -> DecisionRecord | None:
        decision_path = self.decisions_dir / f"{decision_id}.json"
        if not decision_path.exists():
            return None
        return DecisionRecord.model_validate_json(decision_path.read_text(encoding="utf-8"))

    def list_recent(self, limit: int = 20) -> list[DecisionRecord]:
        if limit <= 0 or not self.ledger_path.exists():
            return []
        lines = self.ledger_path.read_text(encoding="utf-8").splitlines()
        records: list[DecisionRecord] = []
        for line in reversed(lines):
            if not line.strip():
                continue
            records.append(DecisionRecord.model_validate_json(line))
            if len(records) >= limit:
                break
        return records

    def read_ledger_text(self) -> str:
        if not self.ledger_path.exists():
            return ""
        return self.ledger_path.read_text(encoding="utf-8")

"""AST-based dependency analysis for initial blast radius scoring."""

from __future__ import annotations

import ast
import json
import re
from dataclasses import dataclass, field
from pathlib import Path

from evidence_gate.decision.models import BlastRadius
from evidence_gate.retrieval.repository import SKIP_DIRS, classify_source_type


@dataclass
class DependencyInfo:
    file_path: str
    imports: set[str] = field(default_factory=set)
    imported_by: set[str] = field(default_factory=set)


class ASTDependencyAnalyzer:
    """Analyze repo imports and derive a conservative blast radius."""

    valid_extensions = {
        ".py",
        ".js",
        ".jsx",
        ".ts",
        ".tsx",
        ".c",
        ".cc",
        ".cpp",
        ".h",
        ".hpp",
    }

    def __init__(self, repo_root: Path):
        self.repo_root = Path(repo_root)
        self.dependencies: dict[str, DependencyInfo] = {}
        self.module_to_file: dict[str, str] = {}
        self.workspace_roots: dict[str, str] = {}

    def build_dependency_graph(self) -> None:
        self.workspace_roots = self._discover_workspace_roots()
        source_files = [
            path
            for path in self.repo_root.rglob("*")
            if path.is_file()
            and path.suffix in self.valid_extensions
            and not any(part in SKIP_DIRS for part in path.parts)
        ]

        for source_file in source_files:
            rel_path = source_file.relative_to(self.repo_root).as_posix()
            module_name = self._file_to_module(source_file)
            self.module_to_file[module_name] = rel_path
            self.dependencies[rel_path] = DependencyInfo(
                file_path=rel_path,
                imports=self._extract_imports(source_file),
            )

        for file_path, dependency in self.dependencies.items():
            for imported_module in dependency.imports:
                target_file = self._resolve_import(imported_module)
                if target_file and target_file in self.dependencies:
                    self.dependencies[target_file].imported_by.add(file_path)

    def impacted_files(self, file_path: str) -> set[str]:
        if file_path not in self.dependencies:
            return {file_path}

        visited: set[str] = set()
        queue = [file_path]
        while queue:
            current = queue.pop()
            if current in visited:
                continue
            visited.add(current)
            dependency = self.dependencies.get(current)
            if dependency is None:
                continue
            for importer in dependency.imported_by:
                if importer not in visited:
                    queue.append(importer)
        return visited

    def dependency_depth(self, file_path: str) -> int:
        if file_path not in self.dependencies:
            return 0

        def _walk(current: str, seen: set[str]) -> int:
            dependency = self.dependencies.get(current)
            if dependency is None:
                return 0
            depth = 0
            for importer in dependency.imported_by:
                if importer in seen:
                    continue
                depth = max(depth, 1 + _walk(importer, seen | {importer}))
            return depth

        return _walk(file_path, {file_path})

    def summarize(self, changed_paths: list[str]) -> BlastRadius:
        impacted: set[str] = set()
        max_depth = 0
        for file_path in changed_paths:
            impacted |= self.impacted_files(file_path)
            max_depth = max(max_depth, self.dependency_depth(file_path))

        tests = 0
        docs = 0
        runbooks = 0
        for path in impacted:
            source_type = classify_source_type(path)
            if source_type.value == "test":
                tests += 1
            elif source_type.value == "doc":
                docs += 1
            elif source_type.value == "runbook":
                runbooks += 1

        return BlastRadius(
            files=len(impacted),
            tests=tests,
            docs=docs,
            runbooks=runbooks,
            max_dependency_depth=max_depth,
            impacted_paths=sorted(impacted),
        )

    def _extract_imports(self, file_path: Path) -> set[str]:
        if file_path.suffix == ".py":
            return self._extract_python_imports(file_path)
        if file_path.suffix in {".js", ".jsx", ".ts", ".tsx"}:
            return self._extract_js_imports(file_path)
        if file_path.suffix in {".c", ".cc", ".cpp", ".h", ".hpp"}:
            return self._extract_cpp_imports(file_path)
        return set()

    def _extract_python_imports(self, file_path: Path) -> set[str]:
        imports: set[str] = set()
        try:
            tree = ast.parse(file_path.read_text(encoding="utf-8"), filename=str(file_path))
        except (OSError, SyntaxError, UnicodeDecodeError):
            return imports
        for node in ast.walk(tree):
            if isinstance(node, ast.Import):
                for alias in node.names:
                    imports.add(alias.name)
            elif isinstance(node, ast.ImportFrom) and node.module:
                imports.add(node.module)
        return imports

    def _extract_js_imports(self, file_path: Path) -> set[str]:
        patterns = [
            r"import\s+(?:.*?\s+from\s+)?['\"]([^'\"]+)['\"]",
            r"require\s*\(\s*['\"]([^'\"]+)['\"]\s*\)",
            r"export\s+(?:.*?\s+from\s+)?['\"]([^'\"]+)['\"]",
        ]
        try:
            content = file_path.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            return set()
        imports: set[str] = set()
        for pattern in patterns:
            imports.update(match.group(1) for match in re.finditer(pattern, content))
        return imports

    def _extract_cpp_imports(self, file_path: Path) -> set[str]:
        try:
            content = file_path.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            return set()
        return {match.group(1) for match in re.finditer(r'#include\s+["<]([^">]+)[">]', content)}

    def _file_to_module(self, file_path: Path) -> str:
        rel_path = file_path.relative_to(self.repo_root)
        parts = list(rel_path.parts)
        if parts:
            parts[-1] = Path(parts[-1]).stem
        if parts and parts[-1] in {"__init__", "index"}:
            parts = parts[:-1]
        return ".".join(parts)

    def _resolve_import(self, imported_module: str) -> str | None:
        normalized = imported_module.replace("./", "").replace("../", "").replace("/", ".")
        if normalized in self.module_to_file:
            return self.module_to_file[normalized]
        for module_name, module_file in self.module_to_file.items():
            if module_name == normalized or module_name.startswith(normalized + ".") or module_name.endswith("." + normalized):
                return module_file
        workspace_match = self._resolve_workspace_import(imported_module)
        if workspace_match is not None:
            return workspace_match
        return None

    def _discover_workspace_roots(self) -> dict[str, str]:
        workspace_roots: dict[str, str] = {}
        for package_json in self.repo_root.rglob("package.json"):
            if any(part in SKIP_DIRS for part in package_json.parts):
                continue
            rel_dir = package_json.parent.relative_to(self.repo_root).as_posix()
            for alias in self._workspace_aliases_for_package_json(package_json, rel_dir):
                workspace_roots.setdefault(alias, rel_dir)
        return workspace_roots

    def _workspace_aliases_for_package_json(self, package_json: Path, rel_dir: str) -> set[str]:
        aliases: set[str] = set()
        try:
            payload = json.loads(package_json.read_text(encoding="utf-8"))
        except (OSError, UnicodeDecodeError, json.JSONDecodeError):
            payload = {}
        package_name = payload.get("name")
        if isinstance(package_name, str) and package_name.strip():
            aliases.add(package_name.strip())
            if package_name.startswith("@") and "/" in package_name:
                aliases.add(package_name.split("/", maxsplit=1)[1])
        parts = Path(rel_dir).parts
        if len(parts) >= 2 and parts[0] in {"packages", "apps", "libs", "playground"}:
            aliases.add(parts[1])
        return aliases

    def _resolve_workspace_import(self, imported_module: str) -> str | None:
        package_name, remainder = self._split_workspace_import(imported_module)
        if not package_name:
            return None
        workspace_root = self.workspace_roots.get(package_name)
        if workspace_root is None and package_name.startswith("@") and "/" in package_name:
            workspace_root = self.workspace_roots.get(package_name.split("/", maxsplit=1)[1])
        if workspace_root is None:
            return None

        if remainder:
            normalized_remainder = remainder.replace("./", "").replace("/", ".")
            candidates = [
                module_file
                for module_name, module_file in self.module_to_file.items()
                if module_file.startswith(f"{workspace_root}/")
                and (
                    module_name.endswith("." + normalized_remainder)
                    or module_name.endswith(normalized_remainder)
                    or Path(module_file).stem == Path(remainder).stem
                )
            ]
            if candidates:
                return min(candidates, key=lambda path: (path.count("/"), len(path)))
        return self._preferred_workspace_entry(workspace_root)

    def _split_workspace_import(self, imported_module: str) -> tuple[str, str]:
        if not imported_module or imported_module.startswith("."):
            return "", ""
        if imported_module.startswith("@"):
            parts = imported_module.split("/")
            if len(parts) < 2:
                return imported_module, ""
            return "/".join(parts[:2]), "/".join(parts[2:])
        package_name, _, remainder = imported_module.partition("/")
        return package_name, remainder

    def _preferred_workspace_entry(self, workspace_root: str) -> str | None:
        preferred_suffixes = (
            "/src/index.ts",
            "/src/index.tsx",
            "/src/index.js",
            "/src/index.jsx",
            "/index.ts",
            "/index.tsx",
            "/index.js",
            "/index.jsx",
        )
        for suffix in preferred_suffixes:
            candidate = f"{workspace_root}{suffix}"
            if candidate in self.dependencies:
                return candidate
        candidates = [
            path
            for path in self.dependencies
            if path.startswith(f"{workspace_root}/")
        ]
        if not candidates:
            return None
        return min(candidates, key=lambda path: ("/src/" not in path, path.count("/"), len(path)))

